/**
 * GA4 + GTM-style Event Instrumentation
 * Loaded only after cookie consent is accepted.
 */

(function () {
    'use strict';

    const CONSENT_ACCEPTED = localStorage.getItem('cookieConsent') === 'accepted';
    if (!CONSENT_ACCEPTED) {
        return;
    }

    const scriptTag = document.querySelector('script[data-ga-id]');
    const gaId = scriptTag ? scriptTag.getAttribute('data-ga-id') : null;
    if (!gaId || gaId === 'G-XXXXXXXXXX') {
        return;
    }

    window.dataLayer = window.dataLayer || [];
    function gtag() {
        window.dataLayer.push(arguments);
    }
    window.gtag = window.gtag || gtag;

    const gaScript = document.createElement('script');
    gaScript.async = true;
    gaScript.src = 'https://www.googletagmanager.com/gtag/js?id=' + encodeURIComponent(gaId);
    document.head.appendChild(gaScript);

    window.gtag('js', new Date());
    window.gtag('config', gaId, {
        anonymize_ip: true,
        cookie_flags: 'SameSite=None;Secure',
        send_page_view: false
    });

    const path = window.location.pathname.replace(/\/+$/, '');
    const pathParts = path.split('/').filter(Boolean);
    const lang = document.documentElement.getAttribute('lang') || pathParts[0] || 'en';
    const slugParts = pathParts.slice(1);
    const slug = slugParts.join('/');
    const hostname = window.location.hostname.toLowerCase();

    function inferAppTargetFromHost(host) {
        if (host.startsWith('run.')) return 'run_analytics';
        if (host.startsWith('swim.')) return 'swim_analytics';
        if (host.startsWith('bike.')) return 'bike_analytics';
        return 'multi';
    }

    function inferPageType() {
        if (!slug || slug === 'index') {
            return hostname === 'analyticszone.app' ? 'home' : 'app_landing';
        }
        if (slug === 'apps' || slug.startsWith('apps/')) {
            return 'apps';
        }
        if (slug === 'blog' || slug === 'blog/index') {
            return 'blog_index';
        }
        if (slug.startsWith('blog/')) {
            return 'blog_article';
        }
        return hostname === 'analyticszone.app' ? 'home' : 'app_landing';
    }

    function inferContentCluster() {
        if (hostname.startsWith('run.')) return 'running';
        if (hostname.startsWith('swim.')) return 'swimming';
        if (hostname.startsWith('bike.')) return 'cycling';
        if (slug.indexOf('privacy') >= 0) return 'privacy';
        return 'comparison';
    }

    function inferPlacement(element) {
        if (!element) return 'hero';
        const explicit = element.getAttribute('data-cta-placement');
        if (explicit) return explicit;

        const appTable = element.closest('[id*="app-hub"], [id*="compare"], [class*="compare"]');
        if (appTable) return 'apps_table';
        if (element.closest('.sticky, .sticky-mobile')) return 'sticky_mobile';
        if (element.closest('.cta-final-section')) return 'end_article';
        if (element.closest('article') || element.closest('.container-narrow')) return 'mid_article';
        return 'hero';
    }

    function inferAppTargetFromUrl(urlValue) {
        try {
            const url = new URL(urlValue, window.location.origin);
            const host = url.hostname.toLowerCase();
            if (host.startsWith('run.')) return 'run_analytics';
            if (host.startsWith('swim.')) return 'swim_analytics';
            if (host.startsWith('bike.')) return 'bike_analytics';
            return 'multi';
        } catch (err) {
            return 'multi';
        }
    }

    function isStoreLink(urlValue) {
        try {
            const url = new URL(urlValue, window.location.origin);
            const host = url.hostname.toLowerCase();
            return host.indexOf('apps.apple.com') >= 0 || host.indexOf('play.google.com') >= 0;
        } catch (err) {
            return false;
        }
    }

    function inferStore(urlValue) {
        try {
            const host = new URL(urlValue, window.location.origin).hostname.toLowerCase();
            if (host.indexOf('apps.apple.com') >= 0) return 'app_store';
            if (host.indexOf('play.google.com') >= 0) return 'google_play';
        } catch (err) {
            return '';
        }
        return '';
    }

    function sanitizeToken(raw) {
        return String(raw || '')
            .toLowerCase()
            .trim()
            .replace(/[^a-z0-9]+/g, '_')
            .replace(/^_+|_+$/g, '') || 'unknown';
    }

    function inferCtaId(element) {
        if (!element) return 'cta_unknown';
        return (
            element.getAttribute('data-cta-id') ||
            element.id ||
            element.getAttribute('aria-label') ||
            element.textContent ||
            'cta_unknown'
        ).trim().slice(0, 80).replace(/\s+/g, '_').toLowerCase();
    }

    function inferPrimaryKeyword() {
        const metaKeywords = document.querySelector('meta[name="keywords"]');
        if (metaKeywords && metaKeywords.content) {
            return metaKeywords.content.split(',')[0].trim().toLowerCase();
        }
        const h1 = document.querySelector('h1');
        if (h1 && h1.textContent) {
            return h1.textContent.trim().toLowerCase();
        }
        return '';
    }

    function shouldTagOutbound(urlValue) {
        try {
            const url = new URL(urlValue, window.location.origin);
            if (url.hostname === window.location.hostname) return false;
            const host = url.hostname.toLowerCase();
            return (
                host.indexOf('apps.apple.com') >= 0 ||
                host.indexOf('play.google.com') >= 0 ||
                host.endsWith('.analyticszone.app')
            );
        } catch (err) {
            return false;
        }
    }

    const pageType = inferPageType();
    const contentCluster = inferContentCluster();
    const defaultAppTarget = inferAppTargetFromHost(hostname);
    const sourcePage = window.location.pathname;

    function pushEvent(eventName, params) {
        const payload = Object.assign({ event: eventName }, params || {});
        window.dataLayer.push(payload);
        if (window.gtag) {
            window.gtag('event', eventName, params || {});
        }
    }

    const campaignTopic = sanitizeToken(slugParts[slugParts.length - 1] || 'home');
    const campaignCluster = sanitizeToken(contentCluster);
    const defaultCampaign = campaignCluster + '_' + campaignTopic;

    function addUtmParams(link) {
        if (!link || !link.href || !shouldTagOutbound(link.href)) return;
        let url;
        try {
            url = new URL(link.href, window.location.origin);
        } catch (err) {
            return;
        }

        if (!url.searchParams.get('utm_source')) {
            url.searchParams.set('utm_source', 'analyticszone_web');
        }
        if (!url.searchParams.get('utm_medium')) {
            url.searchParams.set('utm_medium', 'organic');
        }
        if (!url.searchParams.get('utm_campaign')) {
            url.searchParams.set('utm_campaign', defaultCampaign);
        }
        if (!url.searchParams.get('utm_content')) {
            url.searchParams.set('utm_content', inferPlacement(link));
        }
        link.href = url.toString();
    }

    document.querySelectorAll('a[href]').forEach(addUtmParams);

    pushEvent('page_view', {
        page_type: pageType,
        content_cluster: contentCluster,
        language: lang
    });

    if (pageType === 'blog_article') {
        const articleSlug = sanitizeToken(slug.replace(/^blog\//, ''));
        const primaryKeyword = inferPrimaryKeyword();
        let sent50 = false;
        let sent90 = false;

        const onScroll = function () {
            const doc = document.documentElement;
            const scrollTop = doc.scrollTop || document.body.scrollTop;
            const maxScroll = Math.max(1, (doc.scrollHeight - doc.clientHeight));
            const depth = (scrollTop / maxScroll) * 100;

            if (!sent50 && depth >= 50) {
                sent50 = true;
                pushEvent('article_scroll_50', {
                    article_slug: articleSlug,
                    cluster: contentCluster,
                    primary_keyword: primaryKeyword
                });
            }

            if (!sent90 && depth >= 90) {
                sent90 = true;
                pushEvent('article_scroll_90', {
                    article_slug: articleSlug,
                    cluster: contentCluster,
                    primary_keyword: primaryKeyword
                });
            }
        };
        window.addEventListener('scroll', onScroll, { passive: true });
    }

    const ctaSeen = new Set();
    const ctaObserver = new IntersectionObserver(function (entries) {
        entries.forEach(function (entry) {
            if (!entry.isIntersecting) return;
            const element = entry.target;
            const ctaId = inferCtaId(element);
            if (ctaSeen.has(ctaId)) return;
            ctaSeen.add(ctaId);

            const href = element.getAttribute('href') || '';
            pushEvent('cta_view', {
                cta_id: ctaId,
                page_type: pageType,
                app_target: inferAppTargetFromUrl(href || window.location.href)
            });
        });
    }, { threshold: 0.5 });

    document.querySelectorAll('a.btn, .hero-app-card, [data-cta-id], .btn-primary').forEach(function (el) {
        ctaObserver.observe(el);
    });

    const pricingSeen = new Set();
    const pricingObserver = new IntersectionObserver(function (entries) {
        entries.forEach(function (entry) {
            if (!entry.isIntersecting) return;
            const element = entry.target;
            const id = element.id || element.className || 'pricing';
            if (pricingSeen.has(id)) return;
            pricingSeen.add(id);
            pushEvent('pricing_view', {
                app_target: defaultAppTarget,
                plan_version: element.getAttribute('data-plan-version') || 'default'
            });
        });
    }, { threshold: 0.5 });

    document.querySelectorAll('[id*="pricing"], [class*="pricing"]').forEach(function (el) {
        pricingObserver.observe(el);
    });

    document.addEventListener('click', function (event) {
        const target = event.target.closest('a, button');
        if (!target) return;

        if (target.tagName.toLowerCase() === 'a') {
            addUtmParams(target);
        }

        const ctaLike =
            target.matches('a.btn, button.btn, .hero-app-card, .btn-primary, [data-cta-id]') ||
            !!target.closest('.hero-app-card');

        const href = target.getAttribute('href') || '';
        const placement = inferPlacement(target);
        const ctaId = inferCtaId(target);
        const appTarget = inferAppTargetFromUrl(href || window.location.href);

        if (ctaLike) {
            pushEvent('cta_click', {
                cta_id: ctaId,
                placement: placement,
                app_target: appTarget
            });
        }

        if (href && isStoreLink(href)) {
            let utmCampaign = defaultCampaign;
            try {
                const url = new URL(href, window.location.origin);
                utmCampaign = url.searchParams.get('utm_campaign') || defaultCampaign;
            } catch (err) {
                utmCampaign = defaultCampaign;
            }
            pushEvent('store_click', {
                store: inferStore(href),
                app_target: appTarget,
                source_page: sourcePage,
                cta_id: ctaId,
                utm_campaign: utmCampaign
            });
        }

        const faqRoot = target.closest('[class*="faq"], #faq');
        if (faqRoot) {
            pushEvent('faq_expand', {
                faq_id: target.id || sanitizeToken(target.textContent).slice(0, 60),
                page_type: pageType,
                app_target: defaultAppTarget
            });
        }

        const compareRoot = target.closest('[id*="compare"], [class*="compare"], table');
        if ((pageType === 'apps' || sourcePage.indexOf('/apps') >= 0) && compareRoot) {
            pushEvent('apps_compare_interaction', {
                interaction_type: 'click',
                app_target: appTarget
            });
        }
    });

    document.addEventListener('change', function (event) {
        const compareRoot = event.target.closest('[id*="compare"], [class*="compare"], table');
        if ((pageType === 'apps' || sourcePage.indexOf('/apps') >= 0) && compareRoot) {
            pushEvent('apps_compare_interaction', {
                interaction_type: 'change',
                app_target: defaultAppTarget
            });
        }
    });

    window.trackEvent = function (category, action, label, value) {
        pushEvent(action, {
            event_category: category,
            event_label: label,
            value: value
        });
    };

    window.addEventListener('storage', function (event) {
        if (event.key !== 'cookieConsent') return;
        if (event.newValue !== 'declined' && event.newValue !== null) return;

        document.cookie.split(';').forEach(function (cookie) {
            const name = cookie.split('=')[0].trim();
            if (name.indexOf('_ga') === 0 || name.indexOf('_gid') === 0) {
                document.cookie = name + '=;expires=Thu, 01 Jan 1970 00:00:00 UTC;path=/';
            }
        });
    });
})();
